post.description:
The filter syntax is the same as used in API query PropValuePairs.
<pre>
{ "PropertyName": "Date", "FilterValue": "01-01-2025..31-05-2025" }
{ "PropertyName": "Voucher", "FilterValue": "100;110;129" }
{ "PropertyName": "Name", "FilterValue": "*abc*" }
// For Sorting
{ "PropertyName": "Name", "OrderByDescending": true }
// Skip and Take
{ "Skip": 1000, "Take": 100 }
</pre>
